// Random walk between 0..120 with bursts of noise — exactly the sort of
// fast-changing input where a debounced display is much more readable
// than the raw value.
const prev = context.get('v') ?? 50;
const drift = (Math.random() - 0.5) * 8;
const noise = Math.random() < 0.15 ? (Math.random() - 0.5) * 30 : 0;
const v = Math.max(0, Math.min(120, prev + drift + noise));
context.set('v', v);
msg.payload = { value: +v.toFixed(2), ts: Date.now() };
return msg;

