// Constants — bundled once, shared across portals that reference them.
const CLAMP_MIN = 0;
const CLAMP_MAX = 100;

// Pure helper.
function clamp(n, min, max) {
  return Math.max(min, Math.min(max, n));
}

// Custom React hook — name MUST start with `use` for React's rules of hooks.
// This node groups a constant + a helper + a hook in one block; portals that
// reference any of `clamp`, `useDebounce`, `CLAMP_MIN`, `CLAMP_MAX` pull in
// the whole node.
function useDebounce(value, ms = 300) {
  const [v, setV] = React.useState(value);
  React.useEffect(() => {
    const t = setTimeout(() => setV(value), ms);
    return () => clearTimeout(t);
  }, [value, ms]);
  return v;
}

