function Bar({ value = 0, label = '' }) {
  // Component uses `clamp` from the utility node — selective inclusion picks
  // up the dependency through the components' code, not just the user JSX.
  const pct = clamp(value, CLAMP_MIN, CLAMP_MAX);
  const color = pct > 80 ? 'bg-red-500' : pct > 50 ? 'bg-amber-500' : 'bg-emerald-500';
  return (
    <div className="flex items-center gap-3">
      <div className="w-24 text-xs text-zinc-400 uppercase tracking-wider">{label}</div>
      <div className="flex-1 h-3 bg-zinc-800 rounded-full overflow-hidden">
        <div className={`h-full ${color} transition-all duration-150`} style={{ width: pct + '%' }} />
      </div>
      <div className="w-14 text-right font-mono text-sm tabular-nums text-zinc-200">
        {value.toFixed(1)}
      </div>
    </div>
  );
}

