function App() {
  const { data } = useNodeRed();
  const raw = data?.value ?? 0;

  // Live raw signal vs debounced views at three different windows.
  // `useDebounce` is declared in the fc-portal-utility node — no import.
  const slow100 = useDebounce(raw, 100);
  const slow400 = useDebounce(raw, 400);
  const slow1500 = useDebounce(raw, 1500);

  return (
    <div className="min-h-screen bg-zinc-950 text-zinc-100 p-8 font-sans">
      <h1 className="text-2xl font-light text-amber-400 mb-2">useDebounce</h1>
      <p className="text-sm text-zinc-500 mb-8">
        Custom hook from <code className="text-amber-300">fc-portal-utility</code>. Same noisy 10 Hz input fed through different debounce windows.
      </p>
      <div className="max-w-xl space-y-4">
        <Bar value={raw} label="raw" />
        <Bar value={slow100} label="100 ms" />
        <Bar value={slow400} label="400 ms" />
        <Bar value={slow1500} label="1500 ms" />
      </div>
    </div>
  );
}
